tool.command:
mkdir -p pggb_out pggb_tmp && #set $delim_map = {'hash': '#', 'pipe': '|', 'underscore': '_', 'dot': '.'} #set $delim_char = $delim_map[str($exclude_delim)]
## pggb requires a bgzip-compressed input with samtools .fai/.gzi indices. ## Re-compress if user uploaded a plain-gzip or uncompressed FASTA. #if str($input_fasta.ext).endswith('gz') gunzip -c '$input_fasta' | bgzip -c -@ "\${GALAXY_SLOTS:-1}" > input.fa.gz && #else bgzip -c -@ "\${GALAXY_SLOTS:-1}" '$input_fasta' > input.fa.gz && #end if samtools faidx input.fa.gz &&
## Run pggb. Do not && to the next steps - vg deconstruct may fail ## (e.g. when --vcf-spec doesn't match graph sample names), and we ## still want to ship the GFA + .og which were produced earlier in ## the pipeline. The if-then-fi blocks below hard-error if the ## critical outputs are actually missing. pggb --input-fasta input.fa.gz --output-dir pggb_out --temp-dir pggb_tmp --threads "\${GALAXY_SLOTS:-1}" --segment-length $segment_length --map-pct-id $map_pct_id --n-haplotypes $n_haplotypes --min-match-len $min_match_len --n-mappings $n_mappings --mash-kmer $mash_kmer --exclude-delim '$delim_char' #if str($block_length).strip() --block-length $block_length #end if $no_splits #if str($poa_length_target).strip() --poa-length-target '$poa_length_target' #end if #if str($poa_params_cond.poa_params) == "manual" --poa-params '$poa_params_cond.poa_match,$poa_params_cond.poa_mismatch,$poa_params_cond.poa_gap1,$poa_params_cond.poa_ext1,$poa_params_cond.poa_gap2,$poa_params_cond.poa_ext2' #else --poa-params '$poa_params_cond.poa_params' #end if #if str($poa_padding).strip() --poa-padding $poa_padding #end if $run_abpoa $global_poa $skip_normalization $skip_viz $stats $write_maf $multiqc #if str($vcf_spec).strip() --vcf-spec '$vcf_spec' #end if --names-with-params > pggb.log 2>&1 ;
pggb_exit=\$? ;
## Locate output files (filenames carry hashes / params). ## pggb writes exactly one of each type per run, so globbing is sufficient. echo "--- pggb exit=\$pggb_exit ---" ; ls -la pggb_out/ 2>/dev/null || true ;
cp pggb.log '$output_log' ;
## GFA and .og are critical outputs — hard-fail if missing. gzip -c pggb_out/*.smooth.final.gfa 2>/dev/null > '$output_gfa' || gzip -c pggb_out/*.smooth.fix.gfa > '$output_gfa' ; cp pggb_out/*.smooth.final.og 2>/dev/null '$output_og' || cp pggb_out/*.smooth.fix.og '$output_og' ;
#if not $skip_viz cp pggb_out/*.lay '$output_lay' 2>/dev/null || true ; cp pggb_out/*.draw.png '$output_layout_png' 2>/dev/null || true ; cp pggb_out/*viz_multiqc.png 2>/dev/null '$output_viz_png' || cp pggb_out/*.viz_O*.png '$output_viz_png' 2>/dev/null || true ; #end if
#if str($vcf_spec).strip() cp pggb_out/*.vcf '$output_vcf' 2>/dev/null || true ; #end if
#if $multiqc cp pggb_out/multiqc_report.html '$output_multiqc' 2>/dev/null || true ; #end if
#if $write_maf cp pggb_out/*.smooth.maf '$output_maf' 2>/dev/null || true ; #end if
echo "DONE"
